# Solution: Error Handling in Real Projects

def parse_config(config_str):
    """Parse key=value lines into a dict. Raise ValueError for malformed lines."""
    result = {}
    for line in config_str.strip().split("\n"):
        line = line.strip()
        if not line:
            continue
        if "=" not in line:
            raise ValueError(f"Malformed config line: {line}")
        key, value = line.split("=", 1)
        result[key.strip()] = value.strip()
    return result

def validate_config(config, required_keys):
    """Return a list of keys from required_keys that are missing in config."""
    return [key for key in required_keys if key not in config]

def safe_parse_int(value, field_name="value"):
    """Parse value as int. Raise ValueError with field_name in the message."""
    try:
        return int(value)
    except (ValueError, TypeError):
        raise ValueError(f"Invalid integer for {field_name}: {value!r}")

def process_records(records, processor):
    """Process records collecting results and failures.
    Return dict with "processed" and "failed" lists."""
    processed = []
    failed = []
    for record in records:
        try:
            processed.append(processor(record))
        except Exception as e:
            failed.append({"record": record, "error": str(e)})
    return {"processed": processed, "failed": failed}

